import 'package:flutter/material.dart';
class DeliveryHome extends StatefulWidget{const DeliveryHome({super.key});@override State<DeliveryHome>createState()=>_DeliveryHomeState();}class _DeliveryHomeState extends State<DeliveryHome>{bool online=false;static const actions=['Assigned pickups','Pickup route','Pickup confirmation','Delivery route','Delivery OTP confirmation','Earnings','Profile'];@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('FreshLane Rider')),body:ListView(padding:const EdgeInsets.all(16),children:[Card(color:online?Colors.green.shade50:null,child:SwitchListTile(title:Text(online?'You are online':'You are offline'),subtitle:const Text('Go online to receive shop pickups'),value:online,onChanged:(v)=>setState(()=>online=v))),const SizedBox(height:12),...actions.map((a)=>Card(child:ListTile(leading:const Icon(Icons.route,color:Colors.green),title:Text(a),trailing:const Icon(Icons.chevron_right),onTap:()=>Navigator.push(context,MaterialPageRoute(builder:(_)=>Detail(a)))))]));}}
class Detail extends StatelessWidget{const Detail(this.title,{super.key});final String title;@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:Text(title)),body:Center(child:Text('$title screen')));}
